from dataclasses import dataclass
from typing import Optional
from anthropic import AsyncAnthropic

@dataclass
class AgentResult:
    success: bool
    content: str
    error: Optional[str] = None

    @classmethod
    def empty(cls, error: str) -> "AgentResult":
        return cls(success=False, content="", error=error)

async def optional_summarizer(chunks: list[str], client: AsyncAnthropic) -> AgentResult:
    """Graceful degradation: returns empty result on failure."""
    try:
        combined = "\n".join(chunks[:5])  # limit context
        response = await client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=256,
            system="Summarize these passages in two sentences.",
            messages=[{"role": "user", "content": combined}],
        )
        return AgentResult(success=True, content=response.content[0].text)
    except Exception as exc:
        return AgentResult.empty(str(exc))

async def writer_agent(
    chunks: list[str],
    summary: AgentResult,
    client: AsyncAnthropic,
) -> str:
    """Writer uses summary if available; falls back to raw chunks."""
    if summary.success:
        context = f"Summary:\n{summary.content}\n\nFull chunks:\n" + "\n".join(chunks)
    else:
        # Degraded path: use raw chunks, mention summarizer failed
        context = "[Summary unavailable]\n\nChunks:\n" + "\n".join(chunks[:3])

    response = await client.messages.create(
        model="claude-sonnet-5",
        max_tokens=2048,
        system="Write a report from the provided context.",
        messages=[{"role": "user", "content": context}],
    )
    return response.content[0].text

import asyncio
import logging
from anthropic import AsyncAnthropic, APIStatusError, APIConnectionError

logger = logging.getLogger("retry")

RETRYABLE_STATUS_CODES = {429, 500, 502, 503, 529}

async def with_retry(
    coro_fn,
    *args,
    max_retries: int = 3,
    base_delay: float = 2.0,
    **kwargs,
):
    """Retry a coroutine with exponential backoff on transient errors."""
    last_exc = None
    for attempt in range(max_retries + 1):
        try:
            return await coro_fn(*args, **kwargs)
        except APIStatusError as exc:
            if exc.status_code not in RETRYABLE_STATUS_CODES:
                raise   # non-retryable — propagate immediately
            last_exc = exc
        except APIConnectionError as exc:
            last_exc = exc

        if attempt < max_retries:
            delay = base_delay * (2 ** attempt)
            logger.warning(
                "attempt=%d/%d error=%r retrying_in=%.1fs",
                attempt + 1, max_retries + 1, str(last_exc), delay,
            )
            await asyncio.sleep(delay)

    raise RuntimeError(
        f"Agent failed after {max_retries + 1} attempts. Last error: {last_exc}"
    )

