from langgraph.graph import StateGraph, END
from typing import TypedDict, Optional, Annotated
import operator

class ResilientState(TypedDict):
    query: str
    chunks: Annotated[list[str], operator.add]
    errors: Annotated[list[str], operator.add]   # collect all errors
    draft: str

def retriever_node(state: ResilientState) -> dict:
    try:
        # ... retrieve chunks ...
        return {"chunks": ["retrieved fact 1", "retrieved fact 2"]}
    except Exception as exc:
        return {"errors": [f"retriever: {exc}"], "chunks": []}

def writer_node(state: ResilientState) -> dict:
    if not state["chunks"]:
        # No chunks — write a degraded response
        return {"draft": "[Could not retrieve facts. Generating from general knowledge.]"}
    try:
        # ... write from chunks ...
        return {"draft": "Full report based on retrieved facts."}
    except Exception as exc:
        return {"errors": [f"writer: {exc}"], "draft": ""}

def route_after_write(state: ResilientState) -> str:
    if state["errors"]:
        return "error_reporter"   # log errors and surface them
    return END

def error_reporter_node(state: ResilientState) -> dict:
    # In production: send errors to your observability stack
    for err in state["errors"]:
        print(f"[PIPELINE ERROR] {err}")
    return {}

graph = StateGraph(ResilientState)
graph.add_node("retriever", retriever_node)
graph.add_node("writer", writer_node)
graph.add_node("error_reporter", error_reporter_node)
graph.set_entry_point("retriever")
graph.add_edge("retriever", "writer")
graph.add_conditional_edges("writer", route_after_write, {
    "error_reporter": "error_reporter",
    END: END,
})
graph.add_edge("error_reporter", END)
app = graph.compile()

from langgraph.graph import StateGraph, END
from langgraph.checkpoint.sqlite import SqliteSaver
from typing import TypedDict, Annotated
import operator

class SubResult(TypedDict):
    output: str
    errors: list[str]

def make_retrieval_subgraph() -> StateGraph:
    """Isolated retrieval subsystem with its own error boundary."""
    class RetrievalState(TypedDict):
        query: str
        output: str
        errors: Annotated[list[str], operator.add]

    sg = StateGraph(RetrievalState)

    def fetch_node(state: RetrievalState) -> dict:
        try:
            # ... perform retrieval ...
            return {"output": "retrieved content"}
        except TimeoutError:
            return {"output": "", "errors": ["retrieval_timeout"]}
        except Exception as e:
            return {"output": "", "errors": [f"retrieval_error:{e}"]}

    def rank_node(state: RetrievalState) -> dict:
        if state["errors"]:
            return {}          # skip ranking if fetch failed
        # ... rank results ...
        return {"output": state["output"] + " [ranked]"}

    sg.add_node("fetch", fetch_node)
    sg.add_node("rank", rank_node)
    sg.set_entry_point("fetch")
    sg.add_edge("fetch", "rank")
    sg.add_edge("rank", END)
    return sg.compile()

# Parent graph calls the subgraph as a single node
class PipelineState(TypedDict):
    query: str
    retrieval: SubResult
    final: str
    errors: Annotated[list[str], operator.add]

retrieval_subgraph = make_retrieval_subgraph()

def retrieval_boundary(state: PipelineState) -> dict:
    """Error boundary: calls subgraph and maps results back to parent."""
    result = retrieval_subgraph.invoke({
        "query": state["query"], "output": "", "errors": []
    })
    return {
        "retrieval": {"output": result["output"], "errors": result["errors"]},
        "errors": result["errors"],   # surface to parent
    }
